"use strict";(globalThis.webpackChunkcodeeatcode_github_io=globalThis.webpackChunkcodeeatcode_github_io||[]).push([[6127],{758(e,t,a){a.r(t),a.d(t,{assets:()=>l,contentTitle:()=>i,default:()=>d,frontMatter:()=>r,metadata:()=>n,toc:()=>u});var n=a(9142),o=a(4848),s=a(8453);const r={title:"You Can't Debug What Bedrock Swallowed",slug:"you-cant-debug-what-bedrock-swallowed",date:new Date("2026-05-21T05:00:00.000Z"),authors:["ambersariya"],tags:["ai-engineering","observability","python","opentelemetry"]},i=void 0,l={authorsImageUrls:[void 0]},u=[];function c(e){const t={code:"code",em:"em",p:"p",pre:"pre",...(0,s.R)(),...e.components};return(0,o.jsxs)(o.Fragment,{children:[(0,o.jsx)(t.p,{children:"There's a particular kind of hell reserved for debugging LLM-backed systems that nobody bothered to instrument. You've got a request that took twelve seconds and you don't know if the slow part was your retrieval pipeline, the prompt construction, the Bedrock call itself, or the post-processing that turned the model's output into something you'd actually show a user. You have logs. You have vibes. You have, essentially, nothing."}),"\n",(0,o.jsx)(t.p,{children:"We hit this early on an LLM project and it focused the mind quickly."}),"\n",(0,o.jsx)(t.p,{children:"AWS Bedrock is opaque by design. You send a prompt, you get tokens back, and what happens between those two events isn't your concern. That's fine \u2014 it's not your model to look inside."}),"\n",(0,o.jsxs)(t.p,{children:["The problem is when that opacity bleeds into the code ",(0,o.jsx)(t.em,{children:"you"})," wrote. Your retrieval logic, your prompt templates, your retry handling, your fallback paths \u2014 none of that needs to be a mystery. But without deliberate instrumentation, it becomes one anyway. You end up with a black box you built yourself, which is a considerably more embarrassing situation than the one Bedrock put you in."]}),"\n",(0,o.jsx)(t.p,{children:"Rather than manually sprinkling trace calls everywhere and inevitably missing the interesting bits, I wrote a Python decorator that wraps functions and methods automatically. Every call gets emitted as a span \u2014 class name, method name, duration, outcome \u2014 and it all folds into a single trace you can read in sequence:"}),"\n",(0,o.jsx)(t.pre,{children:(0,o.jsx)(t.code,{className:"language-python",children:'import functools\nimport time\nfrom opentelemetry import trace\n\ntracer = trace.get_tracer(__name__)\n\ndef traced(func):\n    @functools.wraps(func)\n    def wrapper(*args, **kwargs):\n        class_name = args[0].__class__.__name__ if args else ""\n        span_name = f"{class_name}.{func.__name__}" if class_name else func.__name__\n\n        with tracer.start_as_current_span(span_name) as span:\n            start = time.perf_counter()\n            try:\n                result = func(*args, **kwargs)\n                span.set_status(trace.StatusCode.OK)\n                return result\n            except Exception as exc:\n                span.record_exception(exc)\n                span.set_status(trace.StatusCode.ERROR, str(exc))\n                raise\n            finally:\n                span.set_attribute("duration_ms", (time.perf_counter() - start) * 1000)\n    return wrapper\n'})}),"\n",(0,o.jsx)(t.p,{children:"Apply it to the functions you care about and suddenly your trace reads like a story. Vector search: 40ms. Prompt assembly: 2ms. That \"fast\" Bedrock call that's actually 3.8 seconds because you're using a large model with a 6,000-token context and no caching \u2014 that's visible now. The information was always there. You just couldn't see it."}),"\n",(0,o.jsxs)(t.p,{children:["The part I didn't anticipate: OpenTelemetry handles both technical traces ",(0,o.jsx)(t.em,{children:"and"}),' business metrics through the same pipeline. We used it to answer latency questions ("why did this request take four seconds?") and business questions at the same time ("how many users hit the fallback path today?", "what\'s our prompt cache hit rate this week?"). Same instrumentation layer, different dimensions. There\'s something satisfying about a monitoring setup that doesn\'t require you to maintain two separate systems with two separate mental models.']}),"\n",(0,o.jsx)(t.p,{children:"Here's the thing that surprised me most: a well-instrumented LLM pipeline can actually be easier to reason about than a lot of distributed systems. The order of operations is relatively clear, and when every step emits a span, you can read a trace like a timeline. The non-determinism of the model itself is a different problem \u2014 spans won't tell you why the model said what it said \u2014 but at least the plumbing stops being a mystery."}),"\n",(0,o.jsx)(t.p,{children:"The opacity was never really about the LLM. It was about the code around the LLM that we hadn't bothered to make visible."}),"\n",(0,o.jsx)(t.p,{children:"What I took from this: don't leave observability as something to add later when things go wrong. Wire it in from the start \u2014 it's the interface you build for yourself so that when Bedrock starts behaving oddly at 11pm, you have structured data to work with rather than a twelve-second request duration and a shrug."})]})}function d(e={}){const{wrapper:t}={...(0,s.R)(),...e.components};return t?(0,o.jsx)(t,{...e,children:(0,o.jsx)(c,{...e})}):c(e)}},8453(e,t,a){a.d(t,{R:()=>r,x:()=>i});var n=a(6540);const o={},s=n.createContext(o);function r(e){const t=n.useContext(s);return n.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function i(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(o):e.components||o:r(e.components),n.createElement(s.Provider,{value:t},e.children)}},9142(e){e.exports=JSON.parse('{"permalink":"/you-cant-debug-what-bedrock-swallowed","source":"@site/blog/You Cant Debug What Bedrock Swallowed.md","title":"You Can\'t Debug What Bedrock Swallowed","description":"There\'s a particular kind of hell reserved for debugging LLM-backed systems that nobody bothered to instrument. You\'ve got a request that took twelve seconds and you don\'t know if the slow part was your retrieval pipeline, the prompt construction, the Bedrock call itself, or the post-processing that turned the model\'s output into something you\'d actually show a user. You have logs. You have vibes. You have, essentially, nothing.","date":"2026-05-21T05:00:00.000Z","tags":[{"inline":true,"label":"ai-engineering","permalink":"/tags/ai-engineering"},{"inline":true,"label":"observability","permalink":"/tags/observability"},{"inline":true,"label":"python","permalink":"/tags/python"},{"inline":true,"label":"opentelemetry","permalink":"/tags/opentelemetry"}],"readingTime":3,"hasTruncateMarker":true,"authors":[{"name":"Danish Javed","title":"Software Engineer","url":"https://github.com/ambersariya","imageURL":"https://avatars.githubusercontent.com/u/1080238?s=400&u=5d6212c54765773934d34b3e55908846c9cd4a42&v=4","key":"ambersariya","page":null}],"frontMatter":{"title":"You Can\'t Debug What Bedrock Swallowed","slug":"you-cant-debug-what-bedrock-swallowed","date":"2026-05-21T05:00:00.000Z","authors":["ambersariya"],"tags":["ai-engineering","observability","python","opentelemetry"]},"unlisted":false,"prevItem":{"title":"Your Codebase Has Rules. Does CI Know That?","permalink":"/your-codebase-has-rules-does-ci-know-that"},"nextItem":{"title":"TDD Was Solving the Agent Problem Before Agents Existed","permalink":"/tdd-was-solving-the-agent-problem-before-agents-existed"}}')}}]);